#!/usr/bin/env python3
from __future__ import annotations
import json
from pathlib import Path
from report_link_utils import markdown_link
ROOT=Path(__file__).resolve().parents[1]; OUT=ROOT/'docs/reports/project-status-generated.md'
def load(p): return json.loads((ROOT/p).read_text(encoding='utf-8'))
def nav(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(OUT,OUT)}",f"- Research Gaps: {markdown_link(ROOT/'docs/reports/research-gap-report.md',OUT)}",f"- Next Actions: {markdown_link(ROOT/'docs/planning/next-actions.md',OUT)}"]
def main()->int:
 c=load('theory/evaluation/w3-5-candidate-test-result-v1.0.json'); w=load('theory/evaluation/w3-5-specificity-and-discovery-gate.json'); s=load('theory/evaluation/reasoning-and-contrast-scope-v1.0.json'); d=load('theory/evaluation/w3-5-factorization-result-v1.0.json')['dimensions']; x=load('theory/evaluation/w3-5-reasoning-discrimination-result-v1.0.json')['registered_results']; q=load('theory/evaluation/w3-5-fara-specificity-result-v1.0.json')['result']; a=c['axis_counts']['structural_commitment_necessity']
 lines=['# Project Status (Generated)','','## Navigation','',*nav(),'','Generated by `python tools/project_status_report.py`.','','## Current Research Mode','',f"- W3.5 status: `{w['status']}`.",'- Corpus, factorization, registered discrimination, and qualified FARA-specificity are complete.','- Candidate ablation/reconstruction is not complete: 0 of 648 required atomic trials are preserved.','- Structural commitment necessity remains unresolved for all 12 candidates.','- W5 remains blocked.','','## Registered ADJ Results','',f"- Corpus: {len(s['positive_instances'])} positive, {len(s['contrast_instances'])} contrast, {len(s['disputed_instances'])} disputed.",f"- Factorization: `{d['overall_interpretation']}`; expressiveness `{d['expressiveness']}`; translation `{d['translation']}`; cost `{d['cost_relation']}`.",f"- Discrimination: {x['positive']['reasoning_like']}/8 positives reasoning-like; {x['contrast']['nonreasoning_like']}/8 contrasts nonreasoning-like; {x['disputed']['borderline']}/2 disputed borderline.",f"- FARA specificity: `{q['classification']}`; unique capacity `{q['unique_discriminative_capacity_of_fara']}`.",f"- Candidate aggregate: `{c['aggregate_result']}`.",f"- Structural necessity axis: unresolved {a['unresolved']}, supported {a['supported_at_registered_scope']}, refuted {a['refuted_at_registered_scope']}, partial {a['partial']}.",'- Candidate evidence status: preliminary internal adjudication requiring evidence-complete re-execution.','','## Comparative Representation Status','','CRE-001: deterministic comparison complete at its registered retrospective scope under compiler-authored declared interpretations.','','## USD Status','','- Universal structure: unresolved.','- No universal nonexistence, necessity, minimality, or uniqueness conclusion is authorized.','','## Navigation','',*nav()]
 OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(OUT.relative_to(ROOT)); return 0
if __name__=='__main__': raise SystemExit(main())
